CREATE TABLE payments (payment_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, order_created_at TIMESTAMPTZ NOT NULL, user_id UUID NOT NULL REFERENCES users(user_id), amount DECIMAL(10,2) NOT NULL, payment_token_encrypted BYTEA, status VARCHAR(30) NOT NULL DEFAULT 'pending', idempotency_key VARCHAR(64) NOT NULL UNIQUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), FOREIGN KEY(order_id,order_created_at) REFERENCES orders(order_id,created_at));
CREATE TABLE refunds (refund_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, order_created_at TIMESTAMPTZ NOT NULL, payment_id UUID NOT NULL REFERENCES payments(payment_id), amount DECIMAL(10,2) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'initiated', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), FOREIGN KEY(order_id,order_created_at) REFERENCES orders(order_id,created_at));
